window.AMAZON_PRODUCTS={induction:{title:"Prestige Induction Cooktop",image:"/assets/ad-picture/electric-induction.webp",price:"₹2,000",link:"https://amzn.to/4btYEZl"},induction1:{title:"bike key chain",image:"/assets/ad-picture/bell.webp",price:"₹90",link:"https://amzn.to/4lQQcHc"},induction2:{title:"dhoni IPL tshirts",image:"/assets/ad-picture/dhonitshirts.webp",price:"₹250",link:"https://amzn.to/4s8wt7n"}};class AmazonAd extends HTMLElement{constructor(){super(),this.attachShadow({mode:"open"})}connectedCallback(){const n=this.getAttribute("product");window.AMAZON_PRODUCTS[n]?this.shadowRoot.innerHTML=`\n      <style>\n        .card {\n          border: 1px solid #ddd;\n          border-radius: 12px;\n          padding: 12px;\n          width: 220px;\n          font-family: Arial, sans-serif;\n          box-shadow: 0 4px 10px rgba(0,0,0,0.1);\n          text-align: center;\n          transition: 0.3s;\n          margin: auto;\n        }\n\n        .card:hover {\n          transform: translateY(-5px);\n        }\n\n        img {\n          width: 100%;\n          height: auto;\n          border-radius: 8px;\n        }\n\n        .title {\n          font-size: 14px;\n          margin: 10px 0;\n        }\n\n        .price {\n          color: green;\n          font-weight: bold;\n        }\n\n        a {\n          text-decoration: none;\n          color: inherit;\n        }\n\n        .btn {\n          display: inline-block;\n          margin-top: 10px;\n          padding: 8px 12px;\n          background: #ff9900;\n          color: white;\n          border-radius: 6px;\n          font-size: 14px;\n        }\n\n        /* ✅ Tablet */\n        @media (max-width: 768px) {\n          .card {\n            width: 180px;\n            padding: 10px;\n          }\n          .title {\n            font-size: 13px;\n          }\n          .btn {\n            font-size: 13px;\n            padding: 6px 10px;\n          }\n        }\n\n        /* ✅ Mobile */\n        @media (max-width: 480px) {\n          .card {\n            width: 100%;\n            max-width: 300px;\n          }\n          .title {\n            font-size: 12px;\n          }\n          .price {\n            font-size: 14px;\n          }\n          .btn {\n            width: 100%;\n            display: block;\n          }\n        }\n      </style>\n\n      <div class="card">\n        <a href="${window.AMAZON_PRODUCTS[n].link}" target="_blank" rel="noopener noreferrer">\n          <img src="${window.AMAZON_PRODUCTS[n].image}" alt="${window.AMAZON_PRODUCTS[n].title}">\n          <div class="title">${window.AMAZON_PRODUCTS[n].title}</div>\n          <div class="price">${window.AMAZON_PRODUCTS[n].price}</div>\n          <div class="btn">Buy on Amazon</div>\n        </a>\n      </div>\n    `:this.shadowRoot.innerHTML="<p>Product not found</p>"}}customElements.define("amazon-ad",AmazonAd),window.AMAZON_PRODUCTS={induction1:{title:"",image:"/assets/ad-picture/electric-induction.png",price:"₹2,000",link:"https://amzn.to/4bDzlD2"},induction2:{title:"Philips Induction Stove",image:"/assets/ad-picture/philips.png",price:"₹3,499",link:"#"},induction3:{title:"Bajaj Induction Cooktop",image:"/assets/ad-picture/bajaj.png",price:"₹2,799",link:"#"},induction4:{title:"Usha Induction Cooktop",image:"/assets/ad-picture/usha.png",price:"₹2,499",link:"#"}};class AmazonAdsCollection extends HTMLElement{constructor(){super(),this.attachShadow({mode:"open"})}connectedCallback(){let n=this.getAttribute("products");n=n?n.split(","):Object.keys(window.AMAZON_PRODUCTS).slice(0,4);const i=n.map(n=>{const i=window.AMAZON_PRODUCTS[n];return i?`\n        <a href="${i.link}" target="_blank">\n          <div class="card">\n            <img src="${i.image}" />\n            <h4>${i.title}</h4>\n            <div class="price">${i.price}</div>\n            <div class="btn">Buy Now</div>\n          </div>\n        </a>\n      `:""}).join("");this.shadowRoot.innerHTML=`\n      <style>\n        .grid {\n          display: grid;\n          gap: 16px;\n        }\n\n        /* Desktop */\n        @media (min-width: 1024px) {\n          .grid {\n            grid-template-columns: repeat(4, 1fr);\n          }\n        }\n\n        /* Tablet */\n        @media (min-width: 600px) and (max-width: 1023px) {\n          .grid {\n            grid-template-columns: repeat(2, 1fr);\n          }\n        }\n\n        /* Mobile */\n        @media (max-width: 599px) {\n          .grid {\n            grid-template-columns: repeat(1, 1fr);\n          }\n        }\n\n        .card {\n          border: 1px solid #ddd;\n          border-radius: 12px;\n          padding: 12px;\n          text-align: center;\n          font-family: Arial;\n          transition: 0.3s;\n          background: white;\n        }\n\n        .card:hover {\n          transform: translateY(-5px);\n        }\n\n        img {\n          width: 100%;\n          border-radius: 8px;\n        }\n\n        h4 {\n          font-size: 14px;\n          margin: 10px 0;\n        }\n\n        .price {\n          color: green;\n          font-weight: bold;\n        }\n\n        .btn {\n          background: #ff9900;\n          color: white;\n          padding: 8px;\n          display: inline-block;\n          margin-top: 8px;\n          border-radius: 6px;\n          font-size: 13px;\n        }\n\n        a {\n          text-decoration: none;\n        }\n      </style>\n\n      <div class="grid">\n        ${i}\n      </div>\n    `}}customElements.define("amazon-ads-collection",AmazonAdsCollection);